msg.topic = "Generación";
msg.payload = Math.floor(Math.random() * 1000) + 200;

flow.set("generacion", msg.payload);

return msg;

// ============================================
// FUNCIÓN PARA GRÁFICA DE CONSUMO
// Recibe datos desde "suma de circuitos"
// ============================================

// El valor de consumo real viene en msg.payload
let consumoReal = msg.payload;

// Asegurar que sea número
consumoReal = Number(consumoReal);
if (isNaN(consumoReal)) consumoReal = 0;

// Configurar mensaje para la gráfica
msg.topic = "Consumo";
msg.payload = consumoReal;

// Guardar para otros nodos (compatibilidad)
flow.set("consumo", consumoReal);

// Depuración
node.warn(`📊 GRÁFICA CONSUMO REAL: ${consumoReal} W`);

return msg;

let gen = flow.get("generacion");
let con = flow.get("consumo");

if (gen === undefined || con === undefined) {
    return null;
}

let estado = gen > con;
let mensaje = estado ? "ENERGÍA SUFICIENTE" : "CONSUMO EXCESIVO";
let color = estado ? "#00ff00" : "#ff4444";
let fondo = estado ? "#0a2e0a" : "#2a0000";
let emoji = estado ? "✅⚡" : "⚠️🔥";

msg.payload = `
<div style="
    background: ${fondo};
    border-radius: 20px;
    padding: 20px;
    text-align: center;
    border: 2px solid ${color};
    box-shadow: 0 0 20px ${color};
">
    <div style="font-size: 48px;">${emoji}</div>
    <div style="font-size: 22px; font-weight: bold; color: ${color}; margin: 10px 0;">
        ${mensaje}
    </div>
    <div style="font-size: 32px; font-weight: bold;">
        <span style="color: #00ff00;">${gen}</span>
        <span style="color: white;"> vs </span>
        <span style="color: #ff9800;">${con}</span>
    </div>
    <div style="font-size: 18px; margin-top: 10px; color: ${color};">
        ${estado ? `✔ +${gen - con} W` : `⚠ -${con - gen} W`}
    </div>
</div>
`;

return msg;

// Obtener energía del MPPT (no del WiFi)
let energiaMPPT = flow.get("energia_mppt") || 500;

// Obtener factor WiFi
let factorWiFi = flow.get("factor_wifi") || 1;

// Aplicar factor WiFi a la energía
let energiaDC = energiaMPPT * factorWiFi;

let eficiencia = 0.9;
let salida = energiaDC * eficiencia;

msg.payload = Math.round(salida);

node.warn(`Inversor: ${energiaMPPT}W (MPPT) × ${factorWiFi} (WiFi) × 0.9 = ${msg.payload}W`);

// Guardar para otros nodos
flow.set("energia_ac", msg.payload);

return msg;

let gen = flow.get("generacion") || 0;
let con = flow.get("consumo") || 0;

if (gen === 0 || con === 0) {
    return null;
}

// nueva fórmula coherente
let eficiencia = (gen / con) * 100;

// limitar a 100% máximo
if (eficiencia > 100) {
    eficiencia = 100;
}

msg.payload = eficiencia.toFixed(2) + " %";

return msg;

let consumo = msg.payload;

if (consumo > 900) {
    msg.payload = "🔴 Sobreconsumo";
} else if (consumo > 600) {
    msg.payload = "🟡 Consumo medio";
} else {
    msg.payload = "🟢 Consumo normal";
}

return msg;

let entrada = msg.payload;
let salida = entrada * 0.98;

msg.payload = salida;

flow.set("entrada_mcu", entrada);
flow.set("salida_mcu", salida);

return msg;

let entrada = flow.get("entrada_mcu");
let salida = flow.get("salida_mcu");

if (entrada === undefined || salida === undefined) {
    return null;
}

msg.payload = "Entrada: " + entrada.toFixed(2) +
    " W → Salida: " + salida.toFixed(2) + " W";

return msg;

// ============================================
// RADIACIÓN SOLAR (TEMPERATURA LIGADA)
// ============================================

// 1. Generar radiación
let radiacion = Math.floor(Math.random() * 1200);

// 2. Calcular temperatura y porcentajes SEGÚN radiación
let temperatura;
let climaTexto;
let pClima, pVentila, pEquipos, pIlumina;

if (radiacion <= 200) {
    temperatura = 20;
    climaTexto = "🌧️ Nublado";
    pClima = 0.00;
    pVentila = 0.00;
    pEquipos = 0.40;
    pIlumina = 0.60;
}
else if (radiacion <= 400) {
    temperatura = 23;
    climaTexto = "🌥️ Parcial nublado";
    pClima = 0.00;
    pVentila = 0.15;
    pEquipos = 0.35;
    pIlumina = 0.50;
}
else if (radiacion <= 600) {
    temperatura = 25;
    climaTexto = "🌤️ Soleado suave";
    pClima = 0.00;
    pVentila = 0.30;
    pEquipos = 0.35;
    pIlumina = 0.35;
}
else if (radiacion <= 800) {
    temperatura = 27;
    climaTexto = "☀️ Soleado moderado";
    pClima = 0.15;
    pVentila = 0.30;
    pEquipos = 0.30;
    pIlumina = 0.25;
}
else if (radiacion <= 1000) {
    temperatura = 29;
    climaTexto = "🔆 Soleado fuerte";
    pClima = 0.35;
    pVentila = 0.20;
    pEquipos = 0.25;
    pIlumina = 0.20;
}
else {
    temperatura = 32;
    climaTexto = "🔥 Muy caluroso";
    pClima = 0.50;
    pVentila = 0.15;
    pEquipos = 0.20;
    pIlumina = 0.15;
}

// 3. Guardar variables
flow.set("radiacion_solar", radiacion);
flow.set("temperatura", temperatura);
flow.set("clima_texto", climaTexto);
flow.set("p_clima", pClima);
flow.set("p_ventila", pVentila);
flow.set("p_equipos", pEquipos);
flow.set("p_ilumina", pIlumina);

// ============================================
// 4. ENVIAR A MÚLTIPLES SALIDAS
// ============================================

// Salida 1: MPPT (recibe radiación)
let msgMPPT = { payload: radiacion };

// Salida 2: Control Clima (recibe radiación)
let msgControl = { payload: radiacion };

// 5. Depuración
node.warn(`☀️ ${radiacion}W/m² → 🌡️ ${temperatura}°C | ${climaTexto}`);
node.warn(`📊 Aire:${pClima * 100}% | Vent:${pVentila * 100}% | Equip:${pEquipos * 100}% | Luz:${pIlumina * 100}%`);

// Enviar a 2 salidas
return [[msgMPPT], [msgControl]];

// Esta función va ANTES del gauge
let bateria_wh = flow.get("bateria_wh") || 15000;

// Enviar SOLO el número (sin texto, sin porcentaje)
msg.payload = Math.round(bateria_wh);

return msg;

// Energía que llega del inversor
let energiaAC = msg.payload || 0;

// Leer porcentajes desde Control Clima
let pClima = flow.get("p_clima") || 0.40;
let pVentila = flow.get("p_ventila") || 0.15;
let pEquipos = flow.get("p_equipos") || 0.25;
let pIlumina = flow.get("p_ilumina") || 0.20;

// Calcular consumos
let clima = Math.round(energiaAC * pClima);
let equipos = Math.round(energiaAC * pEquipos);
let iluminacion = Math.round(energiaAC * pIlumina);
let ventilacion = Math.round(energiaAC * pVentila);

// Enviar a los 4 circuitos
return [
    { payload: clima },
    { payload: equipos },
    { payload: iluminacion },
    { payload: ventilacion }
];

msg.payload = msg.payload;
flow.set("climatizacion", msg.payload);  // ← SOLO AGREGAS ESTA LÍNEA
return msg;

msg.payload = msg.payload;
flow.set("equipos", msg.payload);  // ← AGREGAR
return msg;

msg.payload = msg.payload;
flow.set("iluminacion", msg.payload);  // ← AGREGAR
return msg;

// Verificar qué llega
node.warn("=== NODO VENTILACION ===");
node.warn("Payload recibido: " + JSON.stringify(msg.payload));

// Extraer el valor
let valor = msg.payload;

// Si es objeto, extraer payload
if (typeof valor === 'object' && valor !== null) {
    valor = valor.payload || valor;
}

// Convertir a número
valor = Number(valor);
if (isNaN(valor)) valor = 0;

// Redondear
msg.payload = Math.round(valor);

// ✅ AGREGAR
flow.set("ventilacion", msg.payload);

node.warn("Ventilación enviando: " + msg.payload + "W");

return msg;

let radiacion = Number(msg.payload);

if (isNaN(radiacion) || radiacion < 0) radiacion = 500;
radiacion = Math.min(radiacion, 1200);

let eficiencia;
if (radiacion < 200) {
    eficiencia = 0.60;
} else if (radiacion < 600) {
    eficiencia = 0.75;
} else {
    eficiencia = 0.85 + (Math.random() * 0.1);
}

let salida = radiacion * eficiencia;

// Para el gauge de potencia (0-1000W)
msg.payload = Math.round(salida);

// Guardar eficiencia como porcentaje (0-100)
let eficienciaPorcentaje = Math.round(eficiencia * 100);
flow.set("eficiencia_mppt", eficienciaPorcentaje);
flow.set("energia_mppt", msg.payload);
flow.set("radiacion_actual", radiacion);

node.warn(`🔆 ${radiacion}W/m² → ${eficienciaPorcentaje}% → ${msg.payload}W`);

return msg;

let radiacion = flow.get("radiacion_actual") || 0;
let eficiencia = flow.get("eficiencia_mppt") || 0;
let potencia = flow.get("energia_mppt") || 0;

// Soles al inicio
let soles = "☀️";
if (radiacion > 800) soles = "☀️☀️☀️";
else if (radiacion > 500) soles = "☀️☀️";
else if (radiacion > 200) soles = "☀️";
else soles = "⛅";

// Rayos al final
let rayos = "⚡";
if (potencia > 700) rayos = "⚡⚡⚡";
else if (potencia > 400) rayos = "⚡⚡";
else if (potencia > 100) rayos = "⚡";
else rayos = "·";

msg.payload = `${soles} ${radiacion} W/m² → ${eficiencia}% → ${rayos} ${potencia} W`;

return msg;

let calidad = Math.random();

let estado = "";
let factor = 1;
let congelar = false;  // ← NUEVA variable

if (calidad > 0.7) {
    estado = "🟢 Señal buena";
    factor = 1;
    congelar = false;   // ← No congelar
} else if (calidad > 0.3) {
    estado = "🟡 Señal inestable";
    factor = 0.5;
    congelar = false;   // ← No congelar
} else {
    estado = "🔴 Sin conexión";
    factor = 0;
    congelar = true;    // ← CONGELAR datos
}

// Guardar valores
flow.set("factor_wifi", factor);
flow.set("estado_wifi", estado);
flow.set("wifi_congelar", congelar);  // ← NUEVO: guardar estado de congelación

// Para el dashboard (texto)
msg.payload = estado;

node.warn(`📡 WiFi: calidad=${Math.round(calidad * 100)}%, factor=${factor}, estado=${estado}, congelar=${congelar}`);

return msg;

// Extraer eficiencia guardada
msg.payload = flow.get("eficiencia_mppt") || 0;
return msg;

// Esta función va ANTES del texto
let bateria_wh = flow.get("bateria_wh") || 15000;
let capacidad = 30000;
let porcentaje = (bateria_wh / capacidad) * 100;

let emoji = porcentaje > 70 ? "🔋🔋🔋" : porcentaje > 30 ? "🔋🔋" : "🪫⚠️";

msg.payload = `${emoji} ${Math.round(porcentaje)}% (${(bateria_wh / 1000).toFixed(1)}/30 kWh)`;

return msg;

let c1 = flow.get("climatizacion") || 0;
let c2 = flow.get("equipos") || 0;
let c3 = flow.get("iluminacion") || 0;
let c4 = flow.get("ventilacion") || 0;

let consumoTotal = c1 + c2 + c3 + c4;
flow.set("consumo_total", consumoTotal);

// ✅ Enviar la SUMA al gauge
msg.payload = consumoTotal;

node.warn(`⚠️ TOTAL CONSUMO: ${c1}+${c2}+${c3}+${c4} = ${consumoTotal} W`);

return msg;

let generacion = flow.get("generacion") || 500;
let consumo = flow.get("consumo_total") || 400;

let capacidadMaxima = 30000;
let bateria_wh = flow.get("bateria_wh") || 15000;

let balance = (generacion - consumo) / 10;
bateria_wh = bateria_wh + balance;
bateria_wh = Math.max(0, Math.min(bateria_wh, capacidadMaxima));

flow.set("bateria_wh", bateria_wh);

node.warn(`🔋 Gen:${generacion}W | Cons:${consumo}W | Bat:${Math.round(bateria_wh)}Wh`);

msg.payload = bateria_wh;
return msg;

let c1 = flow.get("climatizacion") || 0;
let c2 = flow.get("equipos") || 0;
let c3 = flow.get("iluminacion") || 0;
let c4 = flow.get("ventilacion") || 0;

let total = c1 + c2 + c3 + c4;

if (total === 0) {
    msg.payload = 0;
    msg.texto = "Sin datos";
    return msg;
}

let mayor = Math.max(c1, c2, c3, c4);
let porcentaje = Math.round((mayor / total) * 100);

let nombre = "";
if (mayor === c1) nombre = "❄️ Climatización";
else if (mayor === c2) nombre = "💻 Equipos";
else if (mayor === c3) nombre = "💡 Iluminación";
else nombre = "🌬️ Ventilación";

msg.payload = porcentaje;
msg.texto = `${nombre}: ${porcentaje}%`;

return msg;

let rad = flow.get("radiacion_solar") || 600;
msg.payload = rad;
msg.topic = "Radiación";
return msg;

let temp = flow.get("temperatura") || 25;
msg.payload = temp;
msg.topic = "Temperatura";
return msg;

// Recibir radiación desde la Salida 2 de Radiación Solar
let radiacion = msg.payload;

// Si no llegó nada, usar valor por defecto
if (radiacion === undefined || radiacion === null) {
    radiacion = flow.get("radiacion_solar") || 600;
}

// Determinar mensaje según radiación
let mensaje = "";
if (radiacion < 200) {
    mensaje = "🌧️ Día nublado - Sin refrigeración";
} else if (radiacion > 800) {
    mensaje = "🔴 Aire acondicionado ON";
} else {
    mensaje = "🟡 Ventiladores ON";
}

// Enviar al dashboard
msg.payload = mensaje;

// Depuración
node.warn(`📢 CONTROL CLIMA: ${mensaje} (Radiación: ${radiacion} W/m²)`);

return msg;
